async function main() {
  const expected = $env.N8N_ANTITRADER_OUTBOUND_SECRET;
  if (!expected) throw new Error('N8N_ANTITRADER_OUTBOUND_SECRET must be set on n8n');
  const raw = $input.first().json;
  const j = raw.body !== undefined && typeof raw.body === 'object' && !Array.isArray(raw.body) && (raw.body.toE164 !== undefined || raw.body.webhookSecret !== undefined || raw.body.templateName !== undefined)
    ? raw.body
    : raw;
  const hdrs = raw.headers || {};
  const secretHdr = hdrs['x-antitrader-webhook-secret'] || hdrs['X-Antitrader-Webhook-Secret'];
  const secret = j.webhookSecret || secretHdr;
  if (secret !== expected) throw new Error('unauthorized');
  const toRaw = String(j.toE164 || j.to || '').trim();
  const templateName = String(j.templateName || j.template || '').trim();
  const languageCode = String(j.languageCode || j.language || 'en_US').trim();
  if (!toRaw || !templateName) throw new Error('toE164 and templateName are required');
  const digits = toRaw.replace(/\D/g, '');
  if (!digits || digits.length < 8) throw new Error('invalid phone number');
  const token = $env.WHATSAPP_CLOUD_ACCESS_TOKEN;
  const phoneId = $env.WHATSAPP_PHONE_NUMBER_ID;
  const verRaw = String($env.WHATSAPP_GRAPH_API_VERSION || 'v21.0').trim();
  const ver = verRaw.startsWith('v') ? verRaw : 'v' + verRaw;
  if (!token || !phoneId) throw new Error('WHATSAPP_CLOUD_ACCESS_TOKEN and WHATSAPP_PHONE_NUMBER_ID must be set on n8n');
  const url = 'https://graph.facebook.com/' + ver + '/' + phoneId + '/messages';
  const tpl = {
    name: templateName,
    language: { code: languageCode },
  };
  const bodyParams = j.bodyParameters;
  if (Array.isArray(bodyParams) && bodyParams.length > 0) {
    tpl.components = [
      {
        type: 'body',
        parameters: bodyParams.map(function (x) {
          return { type: 'text', text: String(x) };
        }),
      },
    ];
  }
  const payload = {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to: digits,
    type: 'template',
    template: tpl,
  };
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: url,
    headers: {
      Authorization: 'Bearer ' + token,
      'Content-Type': 'application/json',
    },
    body: payload,
    json: true,
  });
  return [{ json: { ok: true, whatsapp: r } }];
}
return await main.call(this);
